var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"핫……!","JPN":"はっ……！","ENG":"*Gasp...!*","TWN":"咳……！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"다행이에요. 오르카 씨. 한동안 깨어나지 않아서 많이 다쳤을까 봐 조마조마했어요.","JPN":"よかった！　オルカさん。しばらく目覚めなかったので、大怪我をしたのではないかと心配していました。","ENG":"Thank goodness, Orca...! I was so worried because you wouldn't wake up.","TWN":"太好了，奧爾卡。你一直沒醒過來，我還擔心你是不是傷得太嚴重呢。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"응. 굉장히 무서운 꿈을 꿨어.","JPN":"うん。とても怖い夢を見た。","ENG":"Hmm. I had a really bad dream.","TWN":"嗯，我做了一個非常可怕的夢。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"꿈이요……?","JPN":"夢ですか……？","ENG":"A dream...?","TWN":"做夢嗎……？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"차갑고 깊은 물 속에서 헤엄치는 꿈.","JPN":"冷たくて深い水の中で泳ぐ夢。","ENG":"In the dream I was swimming in deep, cold water.","TWN":"我夢到我在一個冰冷又深的水裡游泳，"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"다른 사람들을 찾아다녔는데 아무도 없었어. 제시카도, 찰리도, 관리부장도.","JPN":"他の人たちを探し回ったけど誰もいなかった。ジェシカも、チャーリーも、管理部長も。","ENG":"I tried to look for everyone, but no one was there. Not you, Jessica, or even Charlie.","TWN":"我到處去找其他人，卻一個人都沒有。潔西卡、查理、管理部長都不在。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그건 아마… 미안해요. 제가 통화하는 내용을 들어서 그랬을 거예요.","JPN":"それは多分……すみません。私の通話の内容を聞いたせいでしょう。","ENG":"That's because... I'm sorry. I guess my call affected your dream.","TWN":"那可能是因為…對不起，你可能是聽到我談話的內容。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"괜찮아. 관리부장은 잘못 안 했어.","JPN":"大丈夫。管理部長は悪くない。","ENG":"It's okay. You did nothing wrong, Hana.","TWN":"沒事的，不是管理部長的錯。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"베로니카는? 관리부장을 해치지 않았어?","JPN":"ベロニカは？　管理部長に悪いことしなかった？","ENG":"And Veronica? She didn't hurt you?","TWN":"貝洛妮卡呢？她沒傷害你嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 베로니카 씨는 오르카 씨랑 싸우고 나서 곧장 사장님 집무실로 가셨어요.","JPN":"いいえ。ベロニカさんはオルカさんと戦った後、すぐに社長の執務室に向かいました。","ENG":"No. After your fight with her, she went straight into Boss' office.","TWN":"沒有，你倒下後她就立刻去了老闆辦公室。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"게다가 인상이 굉장히 험악해 보이는 분들까지 들이닥치는 바람에……","JPN":"それに、とても険悪な雰囲気の方々まで押し寄せて来て……","ENG":"Then, a few people with stern looks barged in, and...","TWN":"後來又有長得很可怕的人闖進來……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"여기로 도망쳐 온 거예요.","JPN":"ここに逃げてきたのです。","ENG":"We ran away over here.","TWN":"所以我就逃到這裡來囉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"괜찮아. 내가 전부 쫓아낼 테니까.","JPN":"大丈夫。私がみんな追い出すから。","ENG":"It's okay. I'll get rid of them all.","TWN":"別擔心，我會把他們全趕出去。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내 안의 오르카도 소리치고 있어. 지금 당장에라도….","JPN":"私の中のオルカも叫んでる。今すぐにでも……","ENG":"The Orca inside me is screaming. She's telling me to─","TWN":"我裡面的奧爾卡也在吶喊，她說立刻…"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"도망치라고?","JPN":"逃げろって？","ENG":"Run?","TWN":"逃跑嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"여기 있었어? 한참 찾아다녔잖아, 동생.","JPN":"ここにいたの？　妹、探してたよ。","ENG":"So this is where you were hiding! I've been looking all over for you, little sister.","TWN":"原來你在這裡？我找了你好久，妹妹！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"대장에게 혼나서 울적했는데, 그래도 이렇게 만나다니 왠지 감동적이네.","JPN":"隊長に怒られて気分が沈んでたんだけど、こうやって会えるなんてなんだか感動的だね。","ENG":"I was sad because I got scolded by my captain, but now I'm so happy to see you!","TWN":"被隊長那樣一兇我原本心情很鬱卒的，但看到你還是很感動欸！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"동생이요……?","JPN":"妹……？","ENG":"Your sister...?","TWN":"妹妹……？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"대체 누구세요? 지금 무슨 말씀을 하시는 거예요?","JPN":"どちら様でしょうか？　それに何のことですか？","ENG":"Who are you? And what do you mean by that?","TWN":"你到底是誰？你在說什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어머나, 언니. 안 되죠. 자매 간의 감동적인 상봉에 끼어들면.","JPN":"あら、お姉さん。ダメでしょ？　姉妹の感動的な再会を邪魔しちゃ。","ENG":"Oh dear. Don't you know you shouldn't get involved in a touching reunion between sisters?","TWN":"哎唷，姊姊你這樣不行喔！現在可是姊妹重逢的感人時刻欸，怎麼可以插嘴呢！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"자, 그러니까 꼬마야. 너도 자리 좀 비켜 줄래?","JPN":"さて、だからお嬢ちゃん。あなたもちょっとどいてくれる？","ENG":"Now then, you too, little girl. Would you give us a moment?","TWN":"我說小鬼，麻煩你也讓一讓好嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"나는 네 안에 있는 동생만 데려가면 되거든.","JPN":"私はあなたの中にいる妹さえ連れて行ければいいの。","ENG":"You see, I'm here for my sister that's inside you.","TWN":"我只想把你裡面的妹妹帶走。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};